/* eslint-disable no-continue */
import { type MutableRefObject, useCallback, useRef, useState } from 'react';

import pLimit from 'p-limit';
import { useIntl } from 'react-intl';

import backgroundApiProxy from '@onekeyhq/kit/src/background/instance/backgroundApiProxy';
import { useIsEnableTransferAllowList } from '@onekeyhq/kit/src/components/AddressInput/hooks';
import { useAccountData } from '@onekeyhq/kit/src/hooks/useAccountData';
import { usePromiseResult } from '@onekeyhq/kit/src/hooks/usePromiseResult';
import { isAddressOwnedByDeactivatedBotWallet } from '@onekeyhq/kit/src/utils/botWalletAccountUtils';
import {
  getBotWalletDisabledMessage,
  showBotWalletDisabledToast,
} from '@onekeyhq/kit/src/utils/botWalletDisabledToast';
import {
  getBulkSendMinTransferAmount,
  getBulkSendMinTransferDisplayAmount,
} from '@onekeyhq/kit/src/views/BulkSend/utils';
import { ETranslations } from '@onekeyhq/shared/src/locale';
import accountUtils from '@onekeyhq/shared/src/utils/accountUtils';
import networkUtils from '@onekeyhq/shared/src/utils/networkUtils';
import { validateTokenAmount } from '@onekeyhq/shared/src/utils/tokenUtils';
import type { IAddressValidation } from '@onekeyhq/shared/types/address';
import { EReceiverMode } from '@onekeyhq/shared/types/bulkSend';
import type { IToken } from '@onekeyhq/shared/types/token';

import { parseBulkSendAddressLine } from '../../addressLineUtils';

import { ELineAnnotationType, type ILineError } from './LineNumberedTextArea';
import {
  type IBulkSendSelectorAccountItem,
  buildBulkSendSelectorAddressKey,
  resolveBulkSendSelectorFallbackAccount,
  resolveBulkSendSenderFallbackSelection,
  resolveBulkSendSenderSelection,
} from './senderSelectorAccountUtils';

type IUseMultiLineAddressValidationParams = {
  selectedNetworkId: string | undefined;
  selectedToken: IToken | undefined;
  maxLines?: number;
  allowAmounts: boolean;
  requireAmounts?: boolean;
  checkDuplicates: boolean;
  checkAllowlist: boolean;
  selectedAccountId?: string;
  resolveAccountId?: boolean;
  onResolvedAccountIds?: (
    ids: Record<number, { accountId: string; indexedAccountId?: string }>,
  ) => void;
  onDuplicateAddressCountChange?: (count: number) => void;
  duplicateWarningMode?: boolean;
  currentWalletId?: string;
  connectedDeviceIds?: Set<string>;
  selectorAccountItemsRef?: MutableRefObject<
    Record<string, IBulkSendSelectorAccountItem>
  >;
  onErrorsChange?: (errors: ILineError[]) => void;
  rejectDeactivatedBotWalletReceiver?: boolean;
};

function useMultiLineAddressValidation(
  params: IUseMultiLineAddressValidationParams,
) {
  const {
    selectedNetworkId,
    selectedToken,
    maxLines,
    allowAmounts,
    requireAmounts,
    checkDuplicates,
    checkAllowlist,
    // selectedAccountId reserved for future allowlist context
    selectedAccountId: _selectedAccountId,
    resolveAccountId,
    onResolvedAccountIds,
    onDuplicateAddressCountChange,
    duplicateWarningMode = false,
    currentWalletId,
    connectedDeviceIds,
    selectorAccountItemsRef,
    onErrorsChange,
    rejectDeactivatedBotWalletReceiver = false,
  } = params;

  const intl = useIntl();
  const { network } = useAccountData({ networkId: selectedNetworkId });
  const isEnableTransferAllowList = useIsEnableTransferAllowList();
  const onResolvedAccountIdsRef = useRef(onResolvedAccountIds);
  const onDuplicateAddressCountChangeRef = useRef(
    onDuplicateAddressCountChange,
  );
  const onErrorsChangeRef = useRef(onErrorsChange);
  const validationSeqRef = useRef(0);
  onResolvedAccountIdsRef.current = onResolvedAccountIds;
  onDuplicateAddressCountChangeRef.current = onDuplicateAddressCountChange;
  onErrorsChangeRef.current = onErrorsChange;

  const { result: vaultSettings } = usePromiseResult(
    async () =>
      selectedNetworkId
        ? backgroundApiProxy.serviceNetwork.getVaultSettings({
            networkId: selectedNetworkId,
          })
        : undefined,
    [selectedNetworkId],
  );

  const minTransferAmount = getBulkSendMinTransferAmount({
    vaultSettings,
    isNative: selectedToken?.isNative,
  });
  const minTransferDisplayAmount = getBulkSendMinTransferDisplayAmount({
    minTransferAmount,
    tokenDecimals: selectedToken?.decimals,
  });

  const [errors, setErrors] = useState<ILineError[]>([]);

  const validateAddress = useCallback(
    async (
      address: string,
    ): Promise<{ isValid: false; error: string } | IAddressValidation> => {
      const networkId = selectedNetworkId ?? '';
      const result =
        await backgroundApiProxy.serviceValidator.localValidateAddress({
          networkId,
          address: address.trim(),
        });
      if (!result.isValid) {
        // Fetch the network name at validation time to avoid stale names
        // when the user switches networks while addresses are already entered
        let networkName = network?.name ?? '';
        if (networkId && networkId !== network?.id) {
          try {
            const networkInfo =
              await backgroundApiProxy.serviceNetwork.getNetwork({
                networkId,
              });
            networkName = networkInfo.name;
          } catch {
            // fallback to hook value
          }
        }
        return {
          isValid: false,
          error: intl.formatMessage(
            {
              id: ETranslations.wallet_bulk_send_error_invalid_network_address,
            },
            { network: networkName },
          ),
        };
      }
      return result;
    },
    [intl, selectedNetworkId, network?.name, network?.id],
  );

  const validateAmount = useCallback(
    (amount: string): string | boolean => {
      if (!selectedToken) {
        return intl.formatMessage({
          id: ETranslations.wallet_bulk_send_error_token_not_selected,
        });
      }

      const { isValid, error } = validateTokenAmount({
        token: selectedToken,
        amount,
        allowZero: false,
        minAmount:
          minTransferAmount && minTransferAmount !== '0'
            ? minTransferAmount
            : undefined,
        customErrorMessages: {
          emptyAmount: intl.formatMessage({
            id: ETranslations.wallet_bulk_send_error_invalid_amount,
          }),
          invalidAmount: intl.formatMessage({
            id: ETranslations.wallet_bulk_send_error_invalid_amount,
          }),
          negativeAmount: intl.formatMessage({
            id: ETranslations.wallet_bulk_send_error_amount_zero,
          }),
          zeroAmount: intl.formatMessage({
            id: ETranslations.wallet_bulk_send_error_amount_zero,
          }),
          minAmount: intl.formatMessage(
            { id: ETranslations.send_error_minimum_amount },
            {
              amount: minTransferDisplayAmount,
              token: selectedToken.symbol,
            },
          ),
          decimalPlaces: intl.formatMessage(
            {
              id: ETranslations.wallet_bulk_send_error_max_decimal_places,
            },
            { decimals: selectedToken.decimals },
          ),
        },
      });

      if (!isValid && error) {
        return error;
      }

      return true;
    },
    [intl, selectedToken, minTransferAmount, minTransferDisplayAmount],
  );

  const resolveAccountIdForAddress = useCallback(
    async (
      address: string,
      networkId: string,
    ): Promise<
      { accountId: string; indexedAccountId?: string } | { error: string }
    > => {
      const trimmedAddress = address.trim();
      const fallbackAccountItem =
        selectorAccountItemsRef?.current[
          buildBulkSendSelectorAddressKey(trimmedAddress)
        ];

      try {
        const walletAccountItems =
          await backgroundApiProxy.serviceAccount.getAccountNameFromAddress({
            networkId,
            address: trimmedAddress,
          });

        if (walletAccountItems.length === 0) {
          const fallbackResult = await resolveBulkSendSenderFallbackSelection({
            fallbackAccountItem,
            currentWalletId,
            networkId,
            connectedDeviceIds,
          });
          if (fallbackResult) {
            if (fallbackResult.type === 'error') {
              return {
                error: intl.formatMessage({
                  id: fallbackResult.errorMessageId,
                }),
              };
            }

            return {
              accountId: fallbackResult.accountId,
              indexedAccountId: fallbackResult.indexedAccountId,
            };
          }

          return {
            error: intl.formatMessage({
              id: ETranslations.wallet_bulk_send_error_address_not_found,
            }),
          };
        }

        const selection = await resolveBulkSendSenderSelection({
          walletAccountItems,
          currentWalletId,
          networkId,
          connectedDeviceIds,
        });

        if (selection.type === 'error') {
          return {
            error: intl.formatMessage({
              id: selection.errorMessageId,
            }),
          };
        }

        return {
          accountId: selection.accountId,
          indexedAccountId: selection.indexedAccountId,
        };
      } catch (_) {
        const fallbackResult = await resolveBulkSendSenderFallbackSelection({
          fallbackAccountItem,
          currentWalletId,
          networkId,
          connectedDeviceIds,
        });
        if (fallbackResult) {
          if (fallbackResult.type === 'error') {
            return {
              error: intl.formatMessage({
                id: fallbackResult.errorMessageId,
              }),
            };
          }

          return {
            accountId: fallbackResult.accountId,
            indexedAccountId: fallbackResult.indexedAccountId,
          };
        }

        return {
          error: intl.formatMessage({
            id: ETranslations.wallet_bulk_send_error_address_not_found,
          }),
        };
      }
    },
    [intl, currentWalletId, connectedDeviceIds, selectorAccountItemsRef],
  );

  const handleValidateAddresses = useCallback(
    async (value: string, emptyErrorMessageId: ETranslations) => {
      validationSeqRef.current += 1;
      const seq = validationSeqRef.current;
      const isValidationStale = () => validationSeqRef.current !== seq;

      if (!value) {
        setErrors([]);
        onErrorsChangeRef.current?.([]);
        onDuplicateAddressCountChangeRef.current?.(0);
        if (resolveAccountId) {
          onResolvedAccountIdsRef.current?.({});
        }
        return intl.formatMessage({ id: emptyErrorMessageId });
      }

      const lines = value.split('\n');
      const nonEmptyLines = lines.filter((l) => l.trim());
      const lineErrors: ILineError[] = [];
      let duplicateAddressCount = 0;

      // Check max lines limit (based on non-empty lines)
      if (maxLines && nonEmptyLines.length > maxLines) {
        lineErrors.push({
          lineNumber: -1,
          message: intl.formatMessage(
            { id: ETranslations.wallet_bulk_send_error_max_addresses },
            { max: maxLines, current: nonEmptyLines.length },
          ),
        });
        onDuplicateAddressCountChangeRef.current?.(0);
        setErrors(lineErrors);
        onErrorsChangeRef.current?.(lineErrors);
        return lineErrors[0].message;
      }

      let receiverMode: EReceiverMode | undefined;

      // Phase 1: Synchronous validation (format, amounts)
      const addressesToValidate: {
        index: number;
        nonEmptyIndex: number;
        address: string;
      }[] = [];
      let nonEmptyIndex = 0;

      for (let i = 0; i < lines.length; i += 1) {
        const line = lines[i].trim();

        if (!line) {
          continue;
        }
        const currentNonEmptyIndex = nonEmptyIndex;
        nonEmptyIndex += 1;

        const parsedLine = parseBulkSendAddressLine(line);
        if (!parsedLine) {
          continue;
        }
        const currentLineMode = parsedLine.mode;

        // Determine expected mode based on params
        if (receiverMode === undefined) {
          if (!allowAmounts) {
            // Force address-only mode
            receiverMode = EReceiverMode.AddressOnly;
          } else if (requireAmounts) {
            // Force address+amount mode
            receiverMode = EReceiverMode.AddressAndAmount;
          } else {
            // Auto-detect from first line
            receiverMode = currentLineMode;
          }
        }

        // If amounts are not allowed but line has an amount separator, reject
        if (
          !allowAmounts &&
          currentLineMode === EReceiverMode.AddressAndAmount
        ) {
          lineErrors.push({
            lineNumber: i + 1,
            message: intl.formatMessage({
              id: ETranslations.wallet_bulk_send_error_expected_address_only,
            }),
          });
          continue;
        }

        // If amounts are required but line has no amount separator, reject
        if (requireAmounts && currentLineMode === EReceiverMode.AddressOnly) {
          lineErrors.push({
            lineNumber: i + 1,
            message: intl.formatMessage({
              id: ETranslations.wallet_bulk_send_error_expected_address_amount,
            }),
          });
          continue;
        }

        // Check if current line matches the established mode (for auto-detect)
        if (
          !requireAmounts &&
          allowAmounts &&
          currentLineMode !== receiverMode
        ) {
          lineErrors.push({
            lineNumber: i + 1,
            message:
              receiverMode === EReceiverMode.AddressOnly
                ? intl.formatMessage({
                    id: ETranslations.wallet_bulk_send_error_expected_address_only,
                  })
                : intl.formatMessage({
                    id: ETranslations.wallet_bulk_send_error_expected_address_amount,
                  }),
          });
          continue;
        }

        if (parsedLine.mode === EReceiverMode.AddressOnly) {
          addressesToValidate.push({
            index: i,
            nonEmptyIndex: currentNonEmptyIndex,
            address: parsedLine.address,
          });
        } else {
          if (!parsedLine.isValid) {
            lineErrors.push({
              lineNumber: i + 1,
              message: intl.formatMessage({
                id: ETranslations.wallet_bulk_send_error_invalid_format,
              }),
            });
            continue;
          }

          addressesToValidate.push({
            index: i,
            nonEmptyIndex: currentNonEmptyIndex,
            address: parsedLine.address,
          });

          // Validate amount synchronously
          const amountValidationResult = validateAmount(parsedLine.amount);
          if (amountValidationResult !== true) {
            lineErrors.push({
              lineNumber: i + 1,
              message:
                typeof amountValidationResult === 'string'
                  ? amountValidationResult
                  : intl.formatMessage({
                      id: ETranslations.wallet_bulk_send_error_invalid_amount,
                    }),
            });
          }
        }
      }

      // Phase 2: Concurrent address validation with rate limiting and duplicate detection
      const resolvedIds: Record<
        number,
        { accountId: string; indexedAccountId?: string }
      > = {};

      if (addressesToValidate.length > 0) {
        const limit = pLimit(10);
        const validationResults = await Promise.all(
          addressesToValidate.map(
            ({ index, nonEmptyIndex: itemIndex, address }) =>
              limit(async () => {
                const result = await validateAddress(address);
                return { index, nonEmptyIndex: itemIndex, address, result };
              }),
          ),
        );
        if (isValidationStale()) {
          return true;
        }

        const validAddresses: {
          index: number;
          nonEmptyIndex: number;
          address: string;
        }[] = [];
        const seenNormalizedAddresses = new Map<string, number>();

        for (const {
          index,
          nonEmptyIndex: itemIndex,
          address,
          result,
        } of validationResults) {
          if (!result.isValid) {
            lineErrors.push({
              lineNumber: index + 1,
              message:
                'error' in result
                  ? result.error
                  : intl.formatMessage({
                      id: ETranslations.wallet_bulk_send_error_invalid_address,
                    }),
            });
          } else {
            const normalizedAddress = result.normalizedAddress;

            if (checkDuplicates) {
              const seenIndex = seenNormalizedAddresses.get(normalizedAddress);
              if (seenIndex !== undefined) {
                duplicateAddressCount += 1;
                lineErrors.push({
                  lineNumber: index + 1,
                  message: intl.formatMessage(
                    {
                      id: ETranslations.wallet_bulk_send_error_duplicate_address,
                    },
                    { line: seenIndex },
                  ),
                  type: duplicateWarningMode
                    ? ELineAnnotationType.Warning
                    : ELineAnnotationType.Error,
                });
              }

              if (seenIndex === undefined) {
                seenNormalizedAddresses.set(normalizedAddress, index + 1);
                validAddresses.push({
                  index,
                  nonEmptyIndex: itemIndex,
                  address,
                });
              } else if (duplicateWarningMode) {
                // In warning mode, duplicates are still valid (user can confirm)
                validAddresses.push({
                  index,
                  nonEmptyIndex: itemIndex,
                  address,
                });
              }
            } else {
              validAddresses.push({
                index,
                nonEmptyIndex: itemIndex,
                address,
              });
            }
          }
        }

        // Phase 2.5: Resolve accountId for each valid sender address
        if (
          resolveAccountId &&
          validAddresses.length > 0 &&
          selectedNetworkId
        ) {
          const accountIdResults = await Promise.all(
            validAddresses.map(({ index, nonEmptyIndex: itemIndex, address }) =>
              limit(async () => {
                const result = await resolveAccountIdForAddress(
                  address,
                  selectedNetworkId,
                );
                return { index, nonEmptyIndex: itemIndex, result };
              }),
            ),
          );
          if (isValidationStale()) {
            return true;
          }

          for (const {
            index,
            nonEmptyIndex: itemIndex,
            result,
          } of accountIdResults) {
            if ('error' in result) {
              lineErrors.push({
                lineNumber: index + 1,
                message: result.error,
              });
            } else {
              resolvedIds[itemIndex] = {
                accountId: result.accountId,
                indexedAccountId: result.indexedAccountId,
              };
            }
          }
        }

        // Reject any address that resolves to a deactivated Bot Wallet
        // account. The helper resolves owners through the regular address
        // index and falls back to fresh-address resolution for BTC, matching
        // the allowlist resolver below.
        if (
          rejectDeactivatedBotWalletReceiver &&
          validAddresses.length > 0 &&
          selectedNetworkId
        ) {
          const botWalletResults = await Promise.all(
            validAddresses.map(({ index, address }) =>
              limit(async () => {
                const trimmedAddress = address.trim();
                const isDeactivated =
                  await isAddressOwnedByDeactivatedBotWallet({
                    networkId: selectedNetworkId,
                    address: trimmedAddress,
                  });
                return { index, isDeactivated };
              }),
            ),
          );
          if (isValidationStale()) {
            return true;
          }
          let hasDeactivatedBotReceiver = false;
          for (const { index, isDeactivated } of botWalletResults) {
            if (isDeactivated) {
              hasDeactivatedBotReceiver = true;
              lineErrors.push({
                lineNumber: index + 1,
                message: getBotWalletDisabledMessage('beReceiver'),
              });
            }
          }
          if (hasDeactivatedBotReceiver) {
            // Show a single aggregated toast — pasting many lines should not
            // spam one toast per row.
            showBotWalletDisabledToast('beReceiver');
          }
        }

        // Phase 3: Allowlist validation for valid, non-duplicate addresses
        if (
          checkAllowlist &&
          validAddresses.length > 0 &&
          selectedNetworkId &&
          isEnableTransferAllowList
        ) {
          const isEvmNetwork = networkUtils.isEvmNetwork({
            networkId: selectedNetworkId,
          });
          const isBTCNetwork = networkUtils.isBTCNetwork(selectedNetworkId);
          const allowListResults = await Promise.all(
            validAddresses.map(({ index, address }) =>
              limit(async () => {
                const trimmedAddress = address.trim();
                const fallbackAccountItem =
                  selectorAccountItemsRef?.current[
                    buildBulkSendSelectorAddressKey(trimmedAddress)
                  ];

                try {
                  let walletAccountItems: { accountId: string }[] =
                    await backgroundApiProxy.serviceAccount.getAccountNameFromAddress(
                      {
                        networkId: selectedNetworkId,
                        address: trimmedAddress,
                      },
                    );

                  if (walletAccountItems.length === 0 && isBTCNetwork) {
                    walletAccountItems =
                      await backgroundApiProxy.serviceFreshAddress.getAccountNameFromFreshAddress(
                        {
                          address: trimmedAddress,
                          networkId: selectedNetworkId,
                        },
                      );
                  }

                  if (
                    walletAccountItems.some((item) =>
                      accountUtils.isOwnAccount({
                        accountId: item.accountId,
                      }),
                    )
                  ) {
                    return { index, isAllowed: true };
                  }

                  const fallbackResult =
                    await resolveBulkSendSelectorFallbackAccount({
                      fallbackAccountItem,
                      networkId: selectedNetworkId,
                    });
                  if (
                    fallbackResult?.type === 'resolved' &&
                    accountUtils.isOwnAccount({
                      accountId: fallbackResult.accountId,
                    })
                  ) {
                    return { index, isAllowed: true };
                  }
                } catch (e) {
                  console.error(e);
                }

                try {
                  const addressBookItem =
                    await backgroundApiProxy.serviceAddressBook.findItem({
                      networkId: isEvmNetwork ? undefined : selectedNetworkId,
                      address: trimmedAddress,
                    });
                  return {
                    index,
                    isAllowed: !!addressBookItem,
                  };
                } catch (e) {
                  console.error(e);
                }

                return { index, isAllowed: false };
              }),
            ),
          );
          if (isValidationStale()) {
            return true;
          }

          for (const { index, isAllowed } of allowListResults) {
            if (!isAllowed) {
              lineErrors.push({
                lineNumber: index + 1,
                message: intl.formatMessage({
                  id: ETranslations.wallet_bulk_send_error_address_not_in_allowlist,
                }),
                translationId: ETranslations.send_address_not_allowlist_error,
              });
            }
          }
        }

        lineErrors.sort((a, b) => a.lineNumber - b.lineNumber);
      }

      if (isValidationStale()) {
        return true;
      }

      // Notify parent of resolved accountIds
      if (resolveAccountId) {
        onResolvedAccountIdsRef.current?.(resolvedIds);
      }

      setErrors(lineErrors);
      onErrorsChangeRef.current?.(lineErrors);
      onDuplicateAddressCountChangeRef.current?.(
        duplicateWarningMode ? duplicateAddressCount : 0,
      );

      const blockingErrors = lineErrors.filter(
        (error) => error.type !== ELineAnnotationType.Warning,
      );

      if (blockingErrors.length > 0) {
        const maxErrorsToDisplay = 5;
        const errorsToDisplay = blockingErrors.slice(0, maxErrorsToDisplay);
        if (blockingErrors.length > maxErrorsToDisplay) {
          errorsToDisplay.push({
            lineNumber: -1,
            message: intl.formatMessage(
              { id: ETranslations.wallet_bulk_send_error_more_errors },
              { count: blockingErrors.length - maxErrorsToDisplay },
            ),
          });
        }
        return errorsToDisplay
          .map((error) =>
            error.lineNumber === -1
              ? error.message
              : intl.formatMessage(
                  {
                    id: ETranslations.wallet_bulk_send_error_line_with_message,
                  },
                  {
                    lineNumber: error.lineNumber,
                    message: error.message,
                  },
                ),
          )
          .join('\n');
      }
      return true;
    },
    [
      intl,
      isEnableTransferAllowList,
      maxLines,
      selectedNetworkId,
      validateAddress,
      validateAmount,
      allowAmounts,
      requireAmounts,
      checkDuplicates,
      checkAllowlist,
      rejectDeactivatedBotWalletReceiver,
      resolveAccountId,
      resolveAccountIdForAddress,
      duplicateWarningMode,
      selectorAccountItemsRef,
    ],
  );

  return {
    handleValidateAddresses,
    errors,
    validateAddress,
  };
}

export { useMultiLineAddressValidation };
